VALUES
  ('promotion-e0adf6cd-moex-00018', 'promotion-e0adf6cd', 'promotion-e0adf6cd-moex-114-3082b5f1', 'sub-promotion-e0adf6cd-04', NULL, 'single_choice', '關於行政法人之敘述，下列何者正確？', '["行政法人為行政機關，受其設置上級機關之指揮監督", "行政法人之人事、財政自主空間較大，完全排除國家人事、預算、會計及審計法規之適用", "地方自治團體得以自治條例設立地方行政法人", "行政法人依其人事管理規章所進用之人員，為公務人員 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:43+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "110", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "教育行政"}'::jsonb, NULL),
  ('promotion-e0adf6cd-moex-00019', 'promotion-e0adf6cd', 'promotion-e0adf6cd-moex-114-3082b5f1', 'sub-promotion-e0adf6cd-04', NULL, 'single_choice', '關於地方自治團體組織之敘述，下列何者正確？', '["地方政府組織得以自治規則制定", "直轄市政府依據地方制度法擬訂其組織準則後，即可成立該組織", "直轄市政府設立果菜運銷有限公司應以自治條例定之", "市議會組織依憲法自律原則而成立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:43+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "110", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "教育行政"}'::jsonb, NULL),
  ('promotion-e0adf6cd-moex-00020', 'promotion-e0adf6cd', 'promotion-e0adf6cd-moex-114-3082b5f1', 'sub-promotion-e0adf6cd-04', NULL, 'single_choice', '關於行政程序法上職務協助之敘述，下列何者正確？', '["行政機關執行職務，由被請求機關協助執行較為經濟時，須組織法規有明文，始得請求職務協助", "被請求機關應考量協助之行為是否在其權限範圍內", "職務協助與委任、委託不同，屬於短暫性之關係，但仍會涉及權限之移轉", "職務協助須公告其協助之事項以及所提供之協助方式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:43+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "110", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "教育行政"}'::jsonb, NULL),
  ('promotion-e0adf6cd-moex-00021', 'promotion-e0adf6cd', 'promotion-e0adf6cd-moex-114-3082b5f1', 'sub-promotion-e0adf6cd-04', NULL, 'single_choice', '依公務人員考績法及實務見解，有關公務人員考績之敘述，下列何者正確？', '["行政機關對公務人員記大過處分，無懲處權時效之適用", "公務人員不服其服務機關所為考績丙等之評定，應以銓敘部為被告提起行政訴訟", "公務人員之年終考績丁等，效力為一次記兩大過免職", "考績應予免職人員，自確定之日起執行；未確定前，應先行停職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:43+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "110", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "教育行政"}'::jsonb, NULL),
  ('promotion-e0adf6cd-moex-00022', 'promotion-e0adf6cd', 'promotion-e0adf6cd-moex-114-3082b5f1', 'sub-promotion-e0adf6cd-04', NULL, 'single_choice', '公務員甲之職務與下列各項人員或事業間有關，若甲與其成立借貸關係，何者不違反公務員服務法？', '["承包甲任職機關之工程廠商", "受有甲任職機關之上級機關補助者", "與甲任職機關間曾有行政爭訟者", "甲任職機關來往款項之銀行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:43+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "110", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "教育行政"}'::jsonb, NULL),
  ('promotion-e0adf6cd-moex-00023', 'promotion-e0adf6cd', 'promotion-e0adf6cd-moex-114-3082b5f1', 'sub-promotion-e0adf6cd-04', NULL, 'single_choice', '公務人員對於服務機關或人事主管機關所為之行政處分，認為違法或顯然不當，致損害其權利或 利益者，依法得提起何種救濟？', '["審議", "復審", "申訴", "聲明異議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:43+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "110", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "教育行政"}'::jsonb, NULL),
  ('promotion-e0adf6cd-moex-00024', 'promotion-e0adf6cd', 'promotion-e0adf6cd-moex-114-3082b5f1', 'sub-promotion-e0adf6cd-04', NULL, 'single_choice', '依行政程序法規定，有關法規命令與行政規則之敘述，下列何者錯誤？', '["法規命令應有法律之授權", "行政規則具有拘束訂定機關、其下級機關及屬官之效力", "法規命令直接對外發生法律效果，行政規則非直接對外發生法規範效力", "法規命令經發布後未依法函送立法院者無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:43+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "110", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "教育行政"}'::jsonb, NULL),
  ('promotion-e0adf6cd-moex-00025', 'promotion-e0adf6cd', 'promotion-e0adf6cd-moex-114-3082b5f1', 'sub-promotion-e0adf6cd-04', NULL, 'single_choice', '主管機關為推動各機關（構）、公營事業機構節能減碳，依職權訂定獎勵節能要點，各機關（構） 如經主管機關評比為節能措施實施成效良好者，將給予獎勵。關於此要點之法律性質，下列敘述 何者正確？', '["本要點為實現重要公共利益而訂定，適用範圍及於主管機關之外的機關或機構，性質屬法規命令", "本要點為主管機關辦理節能措施評比獎勵之依據，屬機關業務處理的一般性規定，故為指令", "即使相關法規未課予主管機關推動節能減碳措施之義務，其仍可訂定要點執行評比與獎勵", "因獎勵涉及動用國家財政預算，為落實民主原則，應依立法院通過法律明文授權始得辦理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:43+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "110", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "教育行政"}'::jsonb, NULL),
