  ('promotion-e0adf6cd-moex-00027', 'promotion-e0adf6cd', 'promotion-e0adf6cd-moex-114-3082b5f1', 'sub-promotion-e0adf6cd-04', NULL, 'single_choice', '依行政程序法規定，下列何者非屬應予廢止之情形？', '["主管機關核發建築執照後發現申請人於申請時所提出之土地使用同意書為偽造", "主管機關准予變更土地編定時，附記申請人應提出土地使用計畫書並配置必要公共設施，事後 申請人並未履行", "勞動部核發外籍家庭照護工聘用許可後，雇主死亡", "外國人經內政部移民署核發居留許可入境後，其有重大危害公共安全之情形"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:43+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "110", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "教育行政"}'::jsonb, NULL)
